"use client"
import { useState } from "react"
import { apiClient, ChatMessage } from "@/lib/api"

export type FocusMode = "general" | "technical" | "creative" | null

export interface UseChatMessage {
  role: "user" | "ai"
  content: string
}

export function useChat(isAuthenticated: boolean, showAuthModal: (action: 'login' | 'register') => void, focusMode?: FocusMode | null) {
  const [messages, setMessages] = useState<UseChatMessage[]>([])
  const [isStreaming, setIsStreaming] = useState(false)
  const [input, setInput] = useState("")

  const handleSend = async (messageText?: string) => {
    const textToSend = messageText || input.trim()
    if (!textToSend || isStreaming) return

    if (!isAuthenticated) {
      showAuthModal('login')
      return
    }

    setInput("")
    setMessages(prev => [...prev, { role: "user", content: textToSend }])
    setIsStreaming(true)

    try {
      const stream = apiClient.stream({ 
        message: textToSend, 
        stream_tokens: true,
        agent_config: focusMode ? { focus_mode: focusMode } : undefined
      })
      let aiMessage = ""

      for await (const chunk of stream) {
        if (chunk.content) {
          aiMessage += chunk.content
          setMessages(prev => {
            const newMessages = [...prev]
            const lastMsg = newMessages[newMessages.length - 1]
            if (lastMsg && lastMsg.role === 'ai') {
              lastMsg.content = aiMessage
            } else {
              newMessages.push({ role: "ai", content: aiMessage })
            }
            return newMessages
          })
        }
      }
    } catch {
      setMessages(prev => [...prev, {
        role: "ai",
        content: "抱歉，发生了错误。请稍后重试。"
      }])
    } finally {
      setIsStreaming(false)
    }
  }

  return { messages, isStreaming, input, setInput, handleSend }
}
